import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Header from './Header';
import { rfidService } from '../services/rfidService';

const API_ENDPOINTS = [
  {
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDTransactionDetails',
    method: 'POST',
    description: 'Save new RFID transaction details with complete product information including weights, pricing, and status.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-save text-white',
    highlight: 'primary',
    color: '#8E2DE2',
    sampleBody: {
      client_code: "LS000123",
      RFIDNumber: "CZ3506",
      Itemcode: "SAU124",
      category_id: "Gold",
      product_id: "Tops",
      design_id: "Fancy Top",
      purity_id: "22CT",
      grosswt: "20.800",
      stonewt: "0.500",
      diamondheight: "0.250",
      netwt: "19.250",
      box_details: "Box A",
      size: 0,
      stoneamount: "20",
      diamondAmount: "20",
      HallmarkAmount: "35",
      MakingPerGram: "10",
      MakingPercentage: "5",
      MakingFixedAmt: "37",
      MRP: "5000",
      imageurl: "",
      status: "ApiActive"
    }
  },
  {
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDTransactionDetails',
    method: 'POST',
    description: 'Update the status of RFID items (e.g., mark as Sold).',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-edit text-white',
    highlight: 'info',
    color: '#4A00E0',
    sampleBody: {
      client_code: "LS000186",
      RFIDNumber: "CZ3581",
      status: "Sold"
    }
  },
  {
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDTransactionDetails',
    method: 'POST',
    description: 'Retrieve all active RFID transactions for a client.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-search text-white',
    highlight: 'primary',
    color: '#06beb6',
    sampleBody: {
      client_code: "LS000186",
      status: "Active"
    }
  },
  {
    name: 'Delete Labelled Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    description: 'Remove specified items from labelled stock inventory.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-trash text-white',
    highlight: 'danger',
    color: '#d60000',
    sampleBody: {
      ClientCode: "LS000186",
      ItemCodes: ["ITEM001", "ITEM002"]
    }
  }
];

const Dashboard = () => {
  const navigate = useNavigate();
  const [userInfo, setUserInfo] = useState({});
  const [selectedEndpoint, setSelectedEndpoint] = useState(null);
  const [response, setResponse] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const userInfo = JSON.parse(localStorage.getItem('userInfo')) || {};
    setUserInfo(userInfo);
  }, []);

  const handleEndpointClick = (endpoint) => {
    setSelectedEndpoint(endpoint);
    setResponse(null);
  };

  const handleTestEndpoint = async () => {
    if (!selectedEndpoint) return;

    setLoading(true);
    try {
      let result;
      const clientCode = userInfo.ClientCode;

      switch (selectedEndpoint.endpoint) {
        case 'GetRFIDTransactionDetails':
          result = await rfidService.getRFIDTransactions(clientCode);
          break;
        case 'UpdateRFIDTransactionDetails':
          result = await rfidService.updateRFIDTransaction({
            clientCode,
            rfidNumber: 'TEST123',
            status: 'Active'
          });
          break;
        case 'DeleteLabelledStockItems':
          result = await rfidService.deleteLabelledStock(clientCode, ['TEST123']);
          break;
        case 'SaveRFIDTransactionDetails':
          result = await rfidService.saveRFIDTransaction({
            clientCode,
            rfidNumber: 'TEST123',
            itemCode: 'ITEM123',
            categoryId: 'Gold',
            productId: 'Ring',
            designId: 'Classic',
            purityId: '22CT',
            grossWeight: '10.5',
            stoneWeight: '0.5',
            diamondHeight: '0.2',
            netWeight: '9.8',
            boxDetails: 'Box A',
            size: 0,
            stoneAmount: '20',
            diamondAmount: '30',
            hallmarkAmount: '35',
            makingPerGram: '10',
            makingPercentage: '5',
            makingFixedAmount: '37',
            mrp: '5000',
            status: 'ApiActive'
          });
          break;
        default:
          break;
      }

      setResponse(result);
      toast.success('API call successful!');
    } catch (error) {
      console.error('API Error:', error);
      setResponse(error.response?.data || error.message);
      toast.error('API call failed. Please check console for details.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%)'
    }}>
      <Header userInfo={userInfo} />
      <ToastContainer />

      <div className="container py-5">
        <div className="row">
          <div className="col-md-4">
            <div className="card shadow-sm mb-4">
              <div className="card-header bg-primary text-white">
                <h5 className="mb-0">Available API Endpoints</h5>
              </div>
              <div className="list-group list-group-flush">
                {API_ENDPOINTS.map((endpoint) => (
                  <button
                    key={endpoint.endpoint}
                    className={`list-group-item list-group-item-action ${selectedEndpoint?.endpoint === endpoint.endpoint ? 'active' : ''}`}
                    onClick={() => handleEndpointClick(endpoint)}
                  >
                    <div className="d-flex align-items-center">
                      <div className="me-3">
                        <i className={endpoint.icon} style={{
                          padding: '10px',
                          borderRadius: '50%',
                          background: endpoint.color
                        }}></i>
                      </div>
                      <div>
                        <h6 className="mb-1">{endpoint.name}</h6>
                        <small>{endpoint.method} {endpoint.endpoint}</small>
                      </div>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="col-md-8">
            {selectedEndpoint && (
              <div className="card shadow-sm">
                <div className="card-header bg-light">
                  <h5 className="mb-0">{selectedEndpoint.name}</h5>
                </div>
                <div className="card-body">
                  <p className="text-muted">{selectedEndpoint.description}</p>

                  <h6 className="mb-3">Sample Request Body:</h6>
                  <pre className="bg-light p-3 rounded">
                    {JSON.stringify(selectedEndpoint.sampleBody, null, 2)}
                  </pre>

                  <button
                    className="btn btn-primary mt-3"
                    onClick={handleTestEndpoint}
                    disabled={loading}
                  >
                    {loading ? 'Testing...' : 'Test Endpoint'}
                  </button>

                  {response && (
                    <>
                      <h6 className="mt-4 mb-3">Response:</h6>
                      <pre className="bg-light p-3 rounded">
                        {JSON.stringify(response, null, 2)}
                      </pre>
                    </>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
